+    }
+
+    #[test]
+    fn display_contains_only_hex_after_prefix() {
+        let id = ContentId::for_bytes(b"data");
+        let display = format!("{id}");
+        let hex_part = display.strip_prefix("sha256-").unwrap();
+        assert!(hex_part.chars().all(|c| c.is_ascii_hexdigit()));
+    }
